// Combinar script + metadata para el próximo paso
const scriptData = $('🔧 Extraer Script').item.json;
const metaRaw = $input.item.json.choices[0].message.content;

let metadata;
try {
  // Limpiar posibles backticks de markdown
  const clean = metaRaw.replace(/```json/g, '').replace(/```/g, '').trim();
  metadata = JSON.parse(clean);
} catch(e) {
  // Fallback si el JSON falla
  metadata = {
    title: `${scriptData.topic} - Tips y curiosidades`,
    description: `Descubrí todo sobre ${scriptData.topic}. Seguinos para más contenido.`,
    tags: [scriptData.topic, 'tips', 'español', 'shorts', 'viral'],
    hashtags: `#${scriptData.topic.replace(/ /g,'')} #shorts #viral`
  };
}

return {
  script_text: scriptData.script_text,
  topic: scriptData.topic,
  style: scriptData.style,
  filename: scriptData.filename,
  title: metadata.title,
  description: metadata.description + '\n\n' + metadata.hashtags,
  tags: metadata.tags
};

// Parsear el resultado del script Python
const output = $input.item.json.stdout || '';
const prev = $('🔀 Combinar Datos').item.json;

// Buscar el JSON resultado al final del output
const jsonMatch = output.match(/\{[\s\S]*\}\s*$/);
let videoResult = {};

try {
  if (jsonMatch) {
    videoResult = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  videoResult = { success: false, error: 'No se pudo parsear resultado' };
}

if (!videoResult.success) {
  throw new Error('Falló la generación de video: ' + (videoResult.error || output));
}

return {
  ...prev,
  video_path: videoResult.video_path,
  video_filename: videoResult.filename,
  ready_to_upload: true
};

// Guardar log del video generado en archivo JSON
const data = $input.item.json;
const fs = require('fs');

const logEntry = {
  date: new Date().toISOString(),
  topic: data.topic,
  title: data.title,
  filename: data.video_filename,
  path: data.video_path,
  status: 'generated_pending_upload'
};

const logPath = '/app/videos/generated_videos.json';
let logs = [];

try {
  if (fs.existsSync(logPath)) {
    logs = JSON.parse(fs.readFileSync(logPath, 'utf8'));
  }
} catch(e) { logs = []; }

logs.push(logEntry);
fs.writeFileSync(logPath, JSON.stringify(logs, null, 2));

console.log('Video registrado en log:', data.video_filename);
return data;

const data = $input.item.json;

// Mostrar resumen
